 120→// ---------------------------------------------------------------------------
 121→// SSE Stream Helpers
 122→// ---------------------------------------------------------------------------
 123→
 124→export type SSEEvent = {
 125→  event?: string;
 126→  data: string;
 127→};
 128→
 129→/**
 130→ * Collect all SSE events from a streaming proxy response.
 131→ */
 132→export async function collectProxySSEEvents(response: Response): Promise<SSEEvent[]> {
 133→  if (!response.body) {
 134→    throw new Error("No response body for SSE collection");
 135→  }
 136→
 137→  const reader = response.body.getReader();
 138→  const decoder = new TextDecoder();
 139→  const events: SSEEvent[] = [];
 140→  let buffer = "";
 141→
 142→  try {
 143→    while (true) {
 144→      const { done, value } = await reader.read();
 145→      if (done) break;
 146→
 147→      buffer += decoder.decode(value, { stream: true });
 148→      const segments = buffer.split("\n\n");
 149→      buffer = segments.pop() ?? "";
 150→
 151→      for (const segment of segments) {
 152→        const lines = segment.split("\n");
 153→        let eventType: string | undefined;
 154→        let dataLine: string | undefined;
 155→
 156→        for (const line of lines) {
 157→          if (line.startsWith("event: ")) {
 158→            eventType = line.slice(7);
 159→          } else if (line.startsWith("data: ")) {
 160→            dataLine = line.slice(6);
 161→          }
 162→        }
 163→
 164→        if (dataLine !== undefined) {
 165→          events.push({ event: eventType, data: dataLine });
 166→        }
 167→      }
 168→    }
 169→  } finally {
 170→    reader.releaseLock();
 171→  }
 172→
 173→  return events;
 174→}
