 236→/**
 237→ * Create a task record linked to a project and workspace.
 238→ */
 239→export async function createProxyTestTask(
 240→  surreal: Surreal,
 241→  taskId: string,
 242→  projectId: string,
 243→  workspaceId: string,
 244→): Promise<string> {
 245→  const taskRecord = new RecordId("task", taskId);
 246→  const projectRecord = new RecordId("project", projectId);
 247→  const workspaceRecord = new RecordId("workspace", workspaceId);
 248→
 249→  await surreal.query(`CREATE $task CONTENT $content;`, {
 250→    task: taskRecord,
 251→    content: {
 252→      title: `Test Task ${taskId}`,
 253→      status: "open",
 254→      workspace: workspaceRecord,
 255→      created_at: new Date(),
 256→    },
 257→  });
 258→
 259→  // Link task to project
 260→  await surreal.query(`RELATE $task->belongs_to->$project SET added_at = time::now();`, {
 261→    task: taskRecord,
 262→    project: projectRecord,
 263→  });
 264→
 265→  return taskId;
 266→}
