 268→// ---------------------------------------------------------------------------
 269→// Graph Query Helpers
 270→// ---------------------------------------------------------------------------
 271→
 272→export type LlmTraceRecord = {
 273→  id: RecordId;
 274→  model: string;
 275→  input_tokens: number;
 276→  output_tokens: number;
 277→  cache_creation_tokens?: number;
 278→  cache_read_tokens?: number;
 279→  cost_usd: number;
 280→  latency_ms: number;
 281→  stop_reason?: string;
 282→  request_id?: string;
 283→  created_at: Date;
 284→};
