 286→/**
 287→ * Query all LLM traces in a workspace.
 288→ */
 289→export async function getTracesForWorkspace(
 290→  surreal: Surreal,
 291→  workspaceId: string,
 292→): Promise<LlmTraceRecord[]> {
 293→  const workspaceRecord = new RecordId("workspace", workspaceId);
 294→
 295→  const results = await surreal.query(
 296→    `SELECT * FROM trace WHERE ->scoped_to->workspace CONTAINS $ws ORDER BY created_at DESC;`,
 297→    { ws: workspaceRecord },
 298→  );
 299→
 300→  return (results[0] ?? []) as LlmTraceRecord[];
 301→}
