  sessions: RecordId[];
}> {
  const traceRecord = new RecordId("trace", traceId);

  const results = await surreal.query(
    `SELECT
       ->scoped_to->workspace AS workspaces,
       ->attributed_to->task AS tasks,
       <-invoked<-agent_session AS sessions
     FROM $trace;`,
    { trace: traceRecord },
  );

  const row = (results[0] as Array<{
    workspaces: RecordId[];
    tasks: RecordId[];
